export function nextGeneration(liveCells: Cell[]): Cell[] {
  const isLive = (x: number, y: number): boolean =>
    liveCells.some(([cx, cy]) => cx === x && cy === y);
  const countLiveNeighbors = (x: number, y: number): number =>
    NEIGHBOR_OFFSETS.filter(([dx, dy]) => isLive(x + dx, y + dy)).length;
  const survivors = liveCells.filter(([x, y]) => survives(countLiveNeighbors(x, y)));
  const deadNeighbors: Cell[] = [];
  for (const [x, y] of liveCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const nx = x + dx;
      const ny = y + dy;
      if (!isLive(nx, ny) && !deadNeighbors.some(([cx, cy]) => cx === nx && cy === ny)) {
        deadNeighbors.push([nx, ny]);
      }
    }
  }
  const births = deadNeighbors.filter(([x, y]) => countLiveNeighbors(x, y) === 3);
  return [...survivors, ...births];
}

